22	void Script::Merge(const string& s,
23	                   const SpellingProperties& sp,
24	                   const vector<Spelling>& v) {
25	  vector<Spelling>& m((*this)[s]);
26	  for (const Spelling& x : v) {
27	    Spelling y(x);
28	    // 疊加運算結果
29	    y.properties.Compose(sp);
30	    auto e = std::find(m.begin(), m.end(), x);
31	    if (e == m.end()) {
32	      m.push_back(y);
33	    } else {
34	      // 合併屬性
35	      e->properties.Update(y.properties);
36	    }
37	  }
38	}
